12	const resolveEndpoint = (links: any) => {
13	  // TODO: Update our trpc routes so they are more clear.
14	  // This function parses paths like the following and maps them
15	  // to the correct API endpoints.
16	  // - viewer.me - 2 segment paths like this are for logged in requests
17	  // - viewer.public.i18n - 3 segments paths can be public or authed
18	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
19	  return (ctx: any) => {
20	    const parts = ctx.op.path.split(".");
21	    let endpoint;
22	    let path = "";
23	    if (parts.length == 2) {
24	      endpoint = parts[0] as keyof typeof links;
25	      path = parts[1];
26	    } else {
27	      endpoint = parts[1] as keyof typeof links;
28	      path = parts.splice(2, parts.length - 2).join(".");
29	    }
30	    return links[endpoint]({ ...ctx, op: { ...ctx.op, path } });
31	  };
32	};
