3	import { QueryClient } from "@tanstack/react-query";
4	
5	import { TRPCClientError } from "@trpc/client";
6	
7	const MAX_QUERY_RETRIES = 3;
8	
9	const isTRPCClientError = (cause: unknown): cause is TRPCClientError<any> => {
10	  return cause instanceof TRPCClientError;
11	};
12	
13	export const queryClient = new QueryClient({
14	  // these configurations are copied from "packages/trpc/react/trpc.ts"
15	  defaultOptions: {
16	    queries: {
17	      /**
18	       * 1s should be enough to just keep identical query waterfalls low
19	       * @example if one page components uses a query that is also used further down the tree
20	       */
21	      staleTime: 1000,
22	      /**
23	       * Retry `useQuery()` calls depending on this function
24	       */
25	      retry(failureCount, error) {
26	        if (isTRPCClientError(error) && error.data) {
