1	import { useLocale } from "@calcom/lib/hooks/useLocale";
2	import useMediaQuery from "@calcom/lib/hooks/useMediaQuery";
3	import { sessionStorage } from "@calcom/lib/webstorage";
4	import classNames from "@calcom/ui/classNames";
5	import { Badge } from "@calcom/ui/components/badge";
6	import type { IconName } from "@calcom/ui/components/icon";
7	import { Icon } from "@calcom/ui/components/icon";
8	import { SkeletonText } from "@calcom/ui/components/skeleton";
9	import { Tooltip } from "@calcom/ui/components/tooltip";
10	import Link from "next/link";
11	import { usePathname } from "next/navigation";
12	import posthog from "posthog-js";
13	import type React from "react";
14	import { Fragment, useEffect, useState } from "react";
15	import { useShouldDisplayNavigationItem } from "./useShouldDisplayNavigationItem";
16	
17	const usePersistedExpansionState = (itemName: string) => {
18	  const [isExpanded, setIsExpanded] = useState(false);
19	
20	  useEffect(() => {
21	    const stored = sessionStorage.getItem(`nav-expansion-${itemName}`);
22	    if (stored !== null) {
23	      setIsExpanded(JSON.parse(stored));
24	    }
25	  }, [itemName]);
26	
27	  const setPersistedExpansion = (expanded: boolean) => {
28	    setIsExpanded(expanded);
29	    sessionStorage.setItem(`nav-expansion-${itemName}`, JSON.stringify(expanded));
30	  };
31	
32	  return [isExpanded, setPersistedExpansion] as const;
33	};
34	
35	const trackNavigationClick = (itemName: string, parentItemName?: string) => {
36	  posthog.capture("navigation_item_clicked", {
37	    item_name: itemName,
38	    parent_name: parentItemName,
39	  });
40	};
41	
42	export type NavigationItemType = {
43	  name: string;
44	  href: string;
45	  isLoading?: boolean;
46	  onClick?: React.MouseEventHandler<HTMLAnchorElement | HTMLButtonElement>;
47	  target?: HTMLAnchorElement["target"];
48	  badge?: React.ReactNode;
49	  icon?: IconName;
50	  child?: NavigationItemType[];
51	  pro?: true;
52	  onlyMobile?: boolean;
53	  onlyDesktop?: boolean;
54	  moreOnMobile?: boolean;
55	  isCurrent?: ({
56	    item,
57	    isChild,
58	    pathname,
59	  }: {
60	    item: Pick<NavigationItemType, "href">;
61	    isChild?: boolean;
62	    pathname: string | null;
63	  }) => boolean;
64	};
65	
66	const defaultIsCurrent: NavigationItemType["isCurrent"] = ({ isChild, item, pathname }) => {
67	  return isChild ? item.href === pathname : item.href ? (pathname?.startsWith(item.href) ?? false) : false;
68	};
69	
70	export const NavigationItem: React.FC<{
71	  index?: number;
72	  item: NavigationItemType;
73	  isChild?: boolean;
74	}> = (props) => {
75	  const { item, isChild } = props;
76	  const { t, isLocaleReady } = useLocale();
77	  const pathname = usePathname();
78	  const isCurrent: NavigationItemType["isCurrent"] = item.isCurrent || defaultIsCurrent;
79	  const current = isCurrent({ isChild: !!isChild, item, pathname });
80	  const shouldDisplayNavigationItem = useShouldDisplayNavigationItem(props.item);
81	  const [isExpanded, setIsExpanded] = usePersistedExpansionState(item.name);
82	
83	  const isTablet = useMediaQuery("(max-width: 1024px)");
84	  const [isTooltipOpen, setIsTooltipOpen] = useState(false);
85	
86	  if (!shouldDisplayNavigationItem) return null;
87	
88	  const hasChildren = item.child && item.child.length > 0;
89	  const hasActiveChild =
90	    hasChildren && item.child?.some((child) => isCurrent({ isChild: true, item: child, pathname }));
91	  const shouldShowChildren = isExpanded || hasActiveChild || isCurrent({ pathname, isChild, item });
92	  const shouldShowChevron = hasChildren && !hasActiveChild;
93	  const isParentNavigationItem = hasChildren && !isChild;
94	
95	  return (
96	    <Fragment>
97	      {isParentNavigationItem ? (
98	        <Tooltip
99	          side="right"
100	          open={isTooltipOpen}
101	          content={
102	            hasChildren ? (
103	              <div className="stack-y-1 pointer-events-auto flex flex-col p-1">
104	                <span className="text-subtle px-2 text-xs font-semibold uppercase tracking-wide">
105	                  {t(item.name)}
106	                </span>
107	                <div className="flex flex-col gap-1">
108	                  {item.child?.map((childItem) => {
109	                    const childIsCurrent =
110	                      typeof childItem.isCurrent === "function"
111	                        ? childItem.isCurrent({
112	                            isChild: true,
113	                            item: childItem,
114	                            pathname,
115	                          })
116	                        : defaultIsCurrent({
117	                            isChild: true,
118	                            item: childItem,
119	                            pathname,
120	                          });
121	                    return (
122	                      <Link
123	                        key={childItem.name}
124	                        href={childItem.href}
125	                        aria-current={childIsCurrent ? "page" : undefined}
126	                        onClick={() => {
127	                          setIsTooltipOpen(false);
128	                          trackNavigationClick(childItem.name, item.name);
129	                        }}
130	                        className={classNames(
131	                          "group relative block rounded-md px-3 py-1 text-sm font-medium",
132	                          childIsCurrent
133	                            ? "bg-emphasis text-white"
134	                            : "hover:bg-emphasis text-mute hover:text-emphasis"
135	                        )}>
136	                        {t(childItem.name)}
137	                      </Link>
138	                    );
139	                  })}
140	                </div>
141	              </div>
142	            ) : (
143	              t(item.name)
144	            )
145	          }
146	          className="lg:hidden">
147	          <button
148	            data-test-id={item.name}
149	            aria-label={t(item.name)}
150	            aria-expanded={isExpanded}
151	            aria-current={current ? "page" : undefined}
152	            onClick={() => {
153	              if (isTablet && hasChildren) {
154	                setIsTooltipOpen(!isTooltipOpen);
155	              } else {
156	                setIsExpanded(!isExpanded);
157	              }
158	            }}
159	            className={classNames(
160	              "todesktop:py-[7px] text-default group relative flex w-full items-center rounded-md px-2 py-1.5 text-sm font-medium transition",
161	              "aria-[aria-current='page']:bg-transparent!",
162	              "[&[aria-current='page']]:text-emphasis mt-0.5 text-sm",
163	              "md:justify-center lg:justify-start",
164	              isLocaleReady
165	                ? "hover:bg-subtle todesktop:[&[aria-current='page']]:bg-emphasis todesktop:hover:bg-transparent hover:text-emphasis"
166	                : ""
167	            )}>
168	            {item.icon && (
169	              <div className="relative">
170	                <Icon
171	                  name={item.isLoading ? "rotate-cw" : item.icon}
172	                  className={classNames(
173	                    "todesktop:!text-blue-500 h-4 w-4 shrink-0 lg:ltr:mr-2 lg:rtl:ml-2",
174	                    item.isLoading && "animate-spin"
175	                  )}
176	                  aria-hidden="true"
177	                />
178	                {shouldShowChevron && (
179	                  <Icon
180	                    name={isExpanded ? "chevron-up" : "chevron-down"}
181	                    className="absolute -bottom-0.5 -right-0.5 h-2.5 w-2.5 rounded-full bg-subtle p-0.5 lg:hidden"
182	                  />
183	                )}
184	              </div>
185	            )}
186	            {isLocaleReady ? (
187	              <span
188	                className="hidden w-full justify-between truncate text-ellipsis lg:flex"
189	                data-testid={`${item.name}-test`}>
190	                {t(item.name)}
191	                {item.badge && item.badge}
192	              </span>
193	            ) : (
194	              <SkeletonText className="h-[20px] w-full" />
195	            )}
196	            {shouldShowChevron && (
197	              <Icon
198	                name={isExpanded ? "chevron-up" : "chevron-down"}
199	                className="ml-auto hidden h-4 w-4 lg:block"
200	              />
201	            )}
202	          </button>
203	        </Tooltip>
204	      ) : (
205	        <Tooltip side="right" content={t(item.name)} className="lg:hidden">
206	          <Link
207	            data-test-id={item.name}
208	            onClick={() => trackNavigationClick(item.name)}
209	            href={item.href}
210	            aria-label={t(item.name)}
211	            target={item.target}
212	            className={classNames(
213	              "todesktop:py-[7px] text-default group flex items-center rounded-md px-2 py-1.5 text-sm font-medium transition",
214	              item.child
215	                ? `aria-[aria-current='page']:bg-transparent!`
216	                : `[&[aria-current='page']]:bg-emphasis`,
217	              isChild
218	                ? `[&[aria-current='page']]:text-emphasis [&[aria-current='page']]:bg-emphasis hidden h-8 pl-16 lg:flex lg:pl-11 ${
219	                    props.index === 0 ? "mt-0" : "mt-1  hover:mt-1 [&[aria-current='page']]:mt-1"
220	                  }`
221	                : "[&[aria-current='page']]:text-emphasis mt-0.5 text-sm md:justify-center lg:justify-start",
222	              isLocaleReady
223	                ? "hover:bg-subtle todesktop:[&[aria-current='page']]:bg-emphasis todesktop:hover:bg-transparent hover:text-emphasis"
224	                : ""
225	            )}
226	            aria-current={current ? "page" : undefined}>
227	            {item.icon && (
228	              <Icon
229	                name={item.isLoading ? "rotate-cw" : item.icon}
230	                className={classNames(
231	                  "todesktop:!text-blue-500 h-4 w-4 shrink-0 aria-[aria-current='page']:text-inherit lg:ltr:mr-2 lg:rtl:ml-2",
232	                  item.isLoading && "animate-spin"
233	                )}
234	                aria-hidden="true"
235	                aria-current={current ? "page" : undefined}
236	              />
237	            )}
238	            {isLocaleReady ? (
239	              <span
240	                className="hidden w-full justify-between truncate text-ellipsis lg:flex"
241	                data-testid={`${item.name}-test`}>
242	                {t(item.name)}
243	                {item.badge && item.badge}
244	              </span>
245	            ) : (
246	              <SkeletonText className="h-[20px] w-full" />
247	            )}
248	          </Link>
249	        </Tooltip>
250	      )}
251	      {hasChildren && (
252	        <div
253	          className={classNames(
254	            "grid transition-all duration-300 ease-in-out",
255	            shouldShowChildren ? "grid-rows-[1fr] opacity-100 visible" : "grid-rows-[0fr] opacity-0 invisible"
256	          )}
257	          aria-hidden={!shouldShowChildren}>
258	          <div className="overflow-hidden">
259	            {item.child?.map((item, index) => (
260	              <NavigationItem index={index} key={item.name} item={item} isChild />
261	            ))}
262	          </div>
263	        </div>
264	      )}
265	    </Fragment>
266	  );
267	};
268	
269	export const MobileNavigationItem: React.FC<{
270	  item: NavigationItemType;
271	  isChild?: boolean;
272	}> = (props) => {
273	  const { item, isChild } = props;
274	  const pathname = usePathname();
275	  const { t, isLocaleReady } = useLocale();
276	  const isCurrent: NavigationItemType["isCurrent"] = item.isCurrent || defaultIsCurrent;
277	  const current = isCurrent({ isChild: !!isChild, item, pathname });
278	  const shouldDisplayNavigationItem = useShouldDisplayNavigationItem(props.item);
279	
280	  if (!shouldDisplayNavigationItem) return null;
